CREATE DATABASE IF NOT EXISTS novaretail_portfolio;
USE novaretail_portfolio;

DROP TABLE IF EXISTS detalle_pedido;
DROP TABLE IF EXISTS devoluciones;
DROP TABLE IF EXISTS pedidos;
DROP TABLE IF EXISTS sesiones_web;
DROP TABLE IF EXISTS gasto_marketing;
DROP TABLE IF EXISTS clientes;
DROP TABLE IF EXISTS productos;

CREATE TABLE clientes (
    cliente_id INT PRIMARY KEY,
    nombre VARCHAR(100),
    segmento VARCHAR(50),
    ciudad VARCHAR(80),
    provincia VARCHAR(80),
    fecha_registro DATE,
    canal_adquisicion VARCHAR(50)
);

CREATE TABLE productos (
    producto_id INT PRIMARY KEY,
    nombre_producto VARCHAR(150),
    categoria VARCHAR(80),
    subcategoria VARCHAR(80),
    precio DECIMAL(12,2),
    costo DECIMAL(12,2),
    activo TINYINT(1)
);

CREATE TABLE pedidos (
    pedido_id INT PRIMARY KEY,
    cliente_id INT,
    fecha_pedido DATE,
    estado_pedido VARCHAR(50),
    metodo_pago VARCHAR(50),
    canal_venta VARCHAR(50),
    FOREIGN KEY (cliente_id) REFERENCES clientes(cliente_id)
);

CREATE TABLE detalle_pedido (
    detalle_id INT PRIMARY KEY,
    pedido_id INT,
    producto_id INT,
    cantidad INT,
    precio_unitario DECIMAL(12,2),
    descuento_pct DECIMAL(5,2),
    FOREIGN KEY (pedido_id) REFERENCES pedidos(pedido_id),
    FOREIGN KEY (producto_id) REFERENCES productos(producto_id)
);

CREATE TABLE devoluciones (
    devolucion_id INT PRIMARY KEY,
    pedido_id INT,
    producto_id INT,
    fecha_devolucion DATE,
    motivo VARCHAR(100),
    monto_reembolsado DECIMAL(12,2)
);

CREATE TABLE sesiones_web (
    sesion_id INT PRIMARY KEY,
    fecha_sesion DATE,
    canal VARCHAR(50),
    dispositivo VARCHAR(50),
    sesiones INT,
    usuarios INT,
    conversiones INT
);

CREATE TABLE gasto_marketing (
    marketing_id INT PRIMARY KEY,
    fecha DATE,
    canal VARCHAR(50),
    campania VARCHAR(100),
    gasto DECIMAL(12,2)
);


































































